#!/usr/bin/env python3
import os, base64, re as _re

files = [
  ('app\\\\dashboard\\\\page.tsx', ''),
  ('app\\\\tracker\\\\page.tsx', ''),
  ('app\\\\staff\\\\page.tsx', ''),
  ('app\\\\covers\\\\page.tsx', ''),
  ('app\\\\departments\\\\page.tsx', ''),
  ('app\\\\forecast\\\\page.tsx', ''),
  ('app\\\\budget\\\\page.tsx', ''),
  ('app\\\\vat\\\\page.tsx', ''),
  ('app\\\\revenue-split\\\\page.tsx', ''),
  ('app\\\\invoices\\\\page.tsx', ''),
]

for win_path, b64 in files:
    path = win_path.replace("\\\\", os.sep).replace("\\", os.sep)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    content = base64.b64decode(b64).decode("utf-8")
    content = content.replace("useState([])", "useState<any[]>([])")
    content = content.replace("useState(null)", "useState<any>(null)")
    import re as _re
    content = _re.sub(r"as const(\s+as const)+", "as const", content)
    with open(path, "wb") as f:
        f.write(content.encode("utf-8"))
    print(f"Written: {path}")
print("\nDone — git add . && git commit -m \"Fix business switching all pages\" && vercel --prod")
